#!/usr/bin/env node
/** @internal — not part of @hirobius/design-system public API surface. */
/**
 * check-tailwind-token-coverage.mjs
 *
 * Asserts tailwind.config.tokens.cjs (generated by scripts/build-tokens.mjs
 * from hirobius.tokens.json) exposes spacing, screens, borderWidth, and
 * fontSize as theme.extend keys, sourced from HDS tokens instead of left on
 * Tailwind's built-in scale (ISSUE-01, hirobius/hds#125). Without these,
 * `p-4` / `gap-6` / `sm:` / `text-sm` / `border-2` resolve to Tailwind
 * defaults — untouched by the dark/tenant/density cascade — and the
 * `data-density` dial is a no-op for utility-authored components.
 *
 * Per ADR-024 (docs/adr/024-token-utility-bridge-scope.md), every value in
 * all 4 keys must be a `var(--…)` reference (optionally wrapped in
 * `calc(...)`) — never a resolved literal — so the value tracks token edits
 * and, for semantic-tier entries, the tenant/density cascade.
 *
 * NOTE on `screens`: `@media` conditions cannot reference CSS custom
 * properties in any browser (see check-hardcoded-breakpoints.mjs v2), so a
 * var()-valued screen entry is not yet a functional breakpoint. ADR-024
 * requires var() refs here anyway (non-negotiable, applies to all 4 keys);
 * this gate enforces the ADR as written. Flagged as an open question in
 * hirobius/hds#125, not resolved by this gate.
 *
 * Exit codes:
 *   0 — all 4 keys present and populated per the rules above
 *   1 — a key is missing, empty, or has a value violating its rule
 *
 * Run: node scripts/check-tailwind-token-coverage.mjs
 * Or:  pnpm check:tailwind-token-coverage
 */

import { existsSync } from 'node:fs';
import { dirname, join, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';
import { createRequire } from 'node:module';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, '..');
const requireCjs = createRequire(import.meta.url);

// Fixture mode: point at a synthetic mini-root holding a single
// tailwind.config.tokens.cjs (proof-of-firing harness, directory-fixture
// flavor — see docs/guardrails/FIXTURE_DIR_HARNESS.md). No-op in normal
// runs (FIXTURE_DIR unset), so whole-tree behavior is byte-identical.
const FIXTURE_DIR = process.env.FIXTURE_DIR;

const CONFIG_PATH = FIXTURE_DIR
  ? join(FIXTURE_DIR, 'tailwind.config.tokens.cjs')
  : join(ROOT, 'tailwind.config.tokens.cjs');

const VAR_REF = /^(calc\()?var\(--[\w-]+\)/;

function isVarRef(value) {
  return typeof value === 'string' && VAR_REF.test(value);
}

const RULES = {
  spacing: { require: isVarRef, label: 'a var(--…) reference' },
  screens: { require: isVarRef, label: 'a var(--…) reference (ADR-024)' },
  borderWidth: { require: isVarRef, label: 'a var(--…) reference' },
  fontSize: { require: isVarRef, label: 'a var(--…) reference' },
};

export function checkThemeExtend(extend) {
  const violations = [];
  for (const [key, rule] of Object.entries(RULES)) {
    const values = extend[key];
    if (!values || typeof values !== 'object' || Object.keys(values).length === 0) {
      violations.push(`theme.extend.${key} is missing or empty`);
      continue;
    }
    for (const [entryKey, entryValue] of Object.entries(values)) {
      if (!rule.require(entryValue)) {
        violations.push(
          `theme.extend.${key}.${entryKey} = ${JSON.stringify(entryValue)} — expected ${rule.label}`,
        );
      }
    }
  }
  return violations;
}

function main() {
  if (!existsSync(CONFIG_PATH)) {
    console.error(`[check-tailwind-token-coverage] not found: ${CONFIG_PATH}`);
    console.error('Run `pnpm tokens` to generate it.');
    return 1;
  }

  delete requireCjs.cache[requireCjs.resolve(CONFIG_PATH)];
  const { theme } = requireCjs(CONFIG_PATH);
  const violations = checkThemeExtend(theme?.extend ?? {});

  if (violations.length === 0) {
    console.log(
      '✓ check-tailwind-token-coverage — spacing/screens/borderWidth/fontSize all token-sourced.',
    );
    return 0;
  }

  console.error(`✗ check-tailwind-token-coverage — ${violations.length} violation(s):`);
  for (const v of violations) console.error(`  - ${v}`);
  console.error(
    '\ntailwind.config.tokens.cjs is generated by scripts/build-tokens.mjs from ' +
      'hirobius.tokens.json — fix the source token or buildTailwindThemeExtend(), then `pnpm tokens`.',
  );
  return 1;
}

const isMain = process.argv[1] && resolve(process.argv[1]) === fileURLToPath(import.meta.url);
if (isMain) {
  process.exit(main());
}
